import * as async from 'async';
import axios, {AxiosError} from 'axios';
import querystring = require('querystring');

import Node from './Node';
import KnowledgeDatabase from './KnowledgeDatabase';

import parentLog from './log';
const log = parentLog.createChild('WebClient');


export type ErrCallback = (err)=>void;
export type NodeCallback = (err, node?:Node)=>void;
export type NodesCallback = (err, nodes?:Node[])=>void;


/**
 * @description KB service client version of KnowledgeDatabase Class.
 *
 * @class WebClient
 * @memberof jibo.kb
 * @extends {jibo.kb.KnowledgeDatabase}
 * @param {string} kbName Name of this KB slice.
 * @param {string} Base URL of KB service to attach to.
 * @intdocs
 */
export default class WebClient extends KnowledgeDatabase {
    public httpUrl:string;


    /** Create an Error with a good message from an AxiosError object
     *
     * @method jibo.kb.WebClient#_processError
     * @param {AxiosError} err Axios error object.
     * @returns {Error} Error object.
     * @private
     */
    private static _processError(err: AxiosError):Error {
        if (err.response) {
            let description = `HTTP Error Code ${err.response.status}`;
            if (err.response.data) {
                description += err.response.data;
            }
            return new Error(description);
        } else {
            return new Error(err.request
                ? 'No response received'
                : 'Unknown error');
        }
    }


    constructor(kbName:string, httpUrl:string) {
        super(kbName);
        this.httpUrl = httpUrl.replace(/\/$/, ''); // remove trailing slash
    }


    /**
     * Initalize this KnowledgeDatabase slice - currenty does
     * nothing, you do not need to call this.
     *
     * @method jibo.kb.WebClient#init
     * @param {Function} callback Called when finshed.
     * @intdocs
     */
    public init(callback:ErrCallback) {
        setImmediate(callback);
    }


    /**
     * Load a node of a given ID.
     *
     * @method jibo.kb.WebClient#load
     * @param {string} id ID of node to load via the KB service.
     * @param {Function} callback Called with (err, node).
     * @intdocs
     */
    public load(id:string, callback:NodeCallback) {
        let url = this._makeUrl(`/node/load/${id}`);
        axios.get(url).then(
            res => {
                const node = res.data
                    ? this.createNodeFromObject(res.data)
                    : null;  // return `null` if not found
                callback(null, node);
            },
            (err: AxiosError) => {
                log.error('axios.get', url, err);
                callback(WebClient._processError(err));
            },
        );
    }


    /**
     * Load an array of nodes of the given array of IDs.
     *
     * @method jibo.kb.WebClient#loadList
     * @param {string[]} ids IDs of nodes to load via the KB service.
     * @param {Function} callback Called with (err, nodes).
     * @intdocs
     */
    public loadList(ids:string[], callback:NodesCallback) {
        let url = this._makeUrl(`/node/load`);
        axios.post(url, ids).then(
            res => {
                const nodes = res.data
                    ? res.data.map(node =>
                        node ? this.createNodeFromObject(node) : null)
                    : null;  // return `null` if not found
                callback(null, nodes);
            },
            (err: AxiosError) => {
                // If the SSM doesn't support POST to /node/load, do async get
                // calls in parallel
                if (err.response && err.response.status === 400) {
                    log.warn('Deprecation warning: jibo-kb will soon drop support for legacy SSM without /node/load POST endpoint.');
                    async.map(ids, this.load.bind(this), callback);
                } else {
                    log.error('axios.post', url, err);
                    callback(WebClient._processError(err));
                }
            },
        );
    }


    /**
     * Load the root node of this KB slice.
     *
     * @method jibo.kb.WebClient#loadRoot
     * @param {Function} callback Called with (err, rootNode).
     * @intdocs
     */
    public loadRoot(callback:NodeCallback) {
        let url = this._makeUrl(`/node/loadRoot`);
        axios.get(url).then(
            res => {
                const node = res.data
                    ? this.createNodeFromObject(res.data)
                    : null;
                callback(null, node);
            },
            (err: AxiosError) => {
                log.error('axios.get', url, err);
                callback(WebClient._processError(err));
            },
        );
    }


    /**
     * Save a given node into this KB slice.
     *
     * @method jibo.kb.WebClient#save
     * @param {jibo.kb.Node} node The node to be saved.
     * @param {Function} callback Called with (err) when done.
     * @intdocs
     */
    public save(node:Node, callback:ErrCallback) {
        let url = this._makeUrl(`/node/save`);
        axios.post(url, node).then(
            res => {
                if (callback) {
                    callback(null);
                }
            },
            (err: AxiosError) => {
                log.error('axios.post', url, err);
                if (callback) {
                    callback(WebClient._processError(err));
                }
            },
        );
    }


    /**
     * Remove a node from this KB slice.
     *
     * @method jibo.kb.WebClient#remove
     * @param {string|jibo.kb.Node} idOrNode ID string or Node object to be removed.
     * @param {Function} callback Called with (err) when done.
     * @intdocs
     */
    public remove(idOrNode:string|Node, callback:ErrCallback) {
        let id:string = this.toId(idOrNode);
        let url = this._makeUrl(`/node/remove/${id}`);
        axios.delete(url).then(
            res => {
                callback(null);
            },
            (err: AxiosError) => {
                log.error('axios.delete', url, err);
                callback(WebClient._processError(err));
            },
        );
    }


    /**
     * Returns the root directory for this KB slice. Not needed for
     * this Web Client version.
     *
     * @method jibo.kb.WebClient#getDirectory
     * @returns {string} URL for this KB slice just in case something
     * calls this expecting a directory.
     * @intdocs
     */
    public getDirectory():string {
        return this._makeUrl();
    }


    /**
     * Assemble URL from base URL provided to constructor and add the
     * API version and kb name to the path.
     *
     * @method jibo.kb.WebClient#_makeUrl
     * @param {string} addPath Additional path to add to URL after the KB name.
     * @returns {string} Assembled URL.
     * @private
     * @intdocs
     */
    private _makeUrl(addPath=''):string {
        let escapedName = querystring.escape(this.kbName);
        return `${this.httpUrl}/v1/kb/${escapedName}`+addPath;
    }
}
