/** @promisify method decorator
 * Assumes the last argument is suppose to be a callback.  If the last
 * argument isn't a function, then assume the callback was left off on
 * purpose to receive a promise instead. Call the method, wrap it in a
 * promise, and return the promise.
 * Note: only works with callbacks that have one argument or less
 * (other than the err object)
 * @private
 */
export function promisify(target: Object, propertyKey: string, descriptor: TypedPropertyDescriptor<any>):any {
    let originalMethod = descriptor.value; // the original decorated method

    // don't use arrow syntax for this function
    // see http://stackoverflow.com/questions/29775830/how-to-implement-a-typescript-decorator
    descriptor.value = function() {
        let result;
        let args = Array.from(arguments);
        let lastArg = args.slice(-1)[0];
        if (typeof lastArg === 'function') {
            // callback given, call it normally
            result = originalMethod.apply(this, args);  // run the decorated method
        } else {
            // no callback, promisfy it
            result = new Promise( (resolve, reject) => {
                let callback = function(err, arg) {
                    if (err) {
                        reject(err);
                    } else {
                        resolve(arg);
                    }
                };
                let newArgs = args.concat(callback);
                originalMethod.apply(this, newArgs);  // run the decorated method
            });
        }
        return result;
    };

    return descriptor;
}


/** @promisify_4 method decorator
 * Like @promisify, except specifically checks if the 4th argument is
 * a function.
 * @private
 */
export function promisify_4(target: Object, propertyKey: string, descriptor: TypedPropertyDescriptor<any>):any {
    let originalMethod = descriptor.value; // the original decorated method

    // don't use arrow syntax for this function
    // see http://stackoverflow.com/questions/29775830/how-to-implement-a-typescript-decorator
    descriptor.value = function() {
        let result;
        let args = Array.from(arguments);
        let fourthArg = args[4];
        if (typeof fourthArg === 'function') {
            // callback given, call it normally
            result = originalMethod.apply(this, args);  // run the decorated method
        } else {
            // no callback, promisfy it
            let originalThis = this;
            result = new Promise( (resolve, reject) => {
                let callback = function(err, arg) {
                    if (err) {
                        reject(err);
                    } else {
                        resolve(arg);
                    }
                };
                let newArgs = args.concat(callback);
                originalMethod.apply(originalThis, newArgs);  // run the decorated method
            });
        }
        return result;
    };

    return descriptor;
}


/** @deprecate method decorator
 * Outputs a warning message that a method has been deprecated.  Takes
 * one argument, a message string describing the deprecation.
 *
 * The decorator takes the argument just like a function:
 *   @deprecate('foo is bad, use method bar instead')
 * @private
 */
export function deprecate(msg:string) {
    msg = msg === undefined ? '' : msg;
    function warn() {
        let stack = new Error().stack;
        stack = stack.split('\n').splice(4).join('\n');  // note: splicing off one more because of decorator
        if ((console as any).groupCollapsed) {
            (console as any).groupCollapsed("%cDeprecation Warning: %c%s", "color:#614108;background:#fffbe6", "font-weight:normal;color:#614108;background:#fffbe6", msg);
            console.warn(stack);
            console.groupEnd();
        }
        else {
            console.warn("Deprecation Warning:", msg);
            console.warn(stack);
        }
    }
    function doDeprecate(target: Object, propertyKey: string, descriptor: TypedPropertyDescriptor<any>):any {
        let originalMethod = descriptor.value; // the original decorated method
        // don't use arrow syntax for this function
        descriptor.value = function() {
            warn();
            return originalMethod.apply(this, arguments);  // run the decorated method
        };
        return descriptor;
    }
    return doDeprecate;
}
