import async = require('async');
//import * as url from 'url';

import {promisify, promisify_4} from './decorators';
import Cache from './Cache';
import KnowledgeDatabase from './KnowledgeDatabase';
import DatabaseManager from './DatabaseManager';
import WebClient from './WebClient';
import Node from './Node';

import parentLog from './log';
const log = parentLog.createChild('Model');


export type ErrCallback = (err)=>void;
export type NodeCallback = (err, node?:Node)=>void;
export type NodesCallback = (err, nodes?:Node[])=>void;
export type ModelConstructor = new (kbNames:string|string[], httpUrl:string)=>Model;


/** Combine multiple KB slices into one. Model instances are the main
 * interaction point with the Knowledge Base. Methods for following
 * edges between nodes are here.
 *
 * Extend this class to add model specific methods to a Model.
 *
 * @class Model
 * @memberof jibo.kb
 * @param {string|string[]} kbNames KB slice names to use in this
 * model.
 * @param {string} httpUrl Base URL of KB service to use.
 */
export default class Model {
    //usage: registry[key] = classConstructor;
    private static modelClassRegistry:{[kbNames:string]:ModelConstructor} = {};
    public pool:KnowledgeDatabase[];
    public cache:Cache;
    public roots:{[kbName:string]:Node};
    public kbNames:string[];
    public httpUrl:string;


    /** Register a Model subclass to be instantiated for a given KB name
     * list.
     *
     * @method jibo.kb.Model.registerModelClass
     * @static
     * @param {string|string[]} kbNames KB name or name list use this
     * subclass for.
     * @param {Function} classConstructor The constructor function for
     * the subclass.
     * @intdocs
     */
    public static registerModelClass(kbNames:string|string[], classConstructor:ModelConstructor) {
        if (!Array.isArray(kbNames)) {
            kbNames = [kbNames];
        }
        let key = (<string[]>kbNames).join(';');
        let registry = this.modelClassRegistry;
        if (registry[key]) {
            log.warn('registerModelClass: overwriting previous class registered for ', key);
        }
        registry[key] = classConstructor;
    }


    /** Use the given KB slice names to find a Model subclass in the
     * Model subclass registry. Defaults to the plain `Model` object
     * if nothing matches.
     *
     * @method jibo.kb.Model.findModelClass
     * @static
     * @param {string|string[]} kbNames Array of knowledge base slice
     * names.
     * @returns {Function} Model class constructor.
     * @intdocs
     */
    public static findModelClass(kbNames:string|string[]):ModelConstructor {
        if (!Array.isArray(kbNames)) {
            kbNames = [kbNames];
        }
        let key = (<string[]>kbNames).join(';');
        let ModelClass:ModelConstructor = Model;  // unless we find a more specific subclass
        let registry = this.modelClassRegistry;
        if (registry[key]) {
            ModelClass = registry[key];
        }
        return ModelClass;
    }


    constructor(kbNames:string|string[], httpUrl:string=null) {
        this.kbNames = this._toArray(kbNames);
        this.httpUrl = httpUrl;

        this.pool = [];
        if (this.httpUrl) {
            this.kbNames.forEach( (kbName) => {
                let knowledgeDatabase = new WebClient(kbName, this.httpUrl);
                this.pool.push(knowledgeDatabase);
            });
        }
    }


    /** Initalize the model and all its kb slices.
     * Not needed when using the KB service as a client.
     *
     * @method jibo.kb.Model#init
     * @param {Function} callback Callback for the method.
     * @intdocs
     */
    public init(callback:ErrCallback) {
        if (this.httpUrl) {
            setImmediate(callback);
        } else {
            let tasks:AsyncFunction<KnowledgeDatabase>[] = [];
            this.kbNames.forEach( (kbName) => {
                tasks.push( (next) => {
                    DatabaseManager.get(kbName, next);
                });
            });
            async.series(tasks, (err, results:KnowledgeDatabase[]) => {
                log.iferr(err, 'KnowledgeDatabase#init');
                if (!err) {
                    this.pool = results;
                }
                callback(err);
            });
        }
    }


    /** Create a new Model object.
     *
     * This behaves the same as `kb.createModel()`, except the KB
     * names are not required to start with /. KB names that don't
     * start with / will be relative to this Model. Specifically, they
     * will relative to the KB name of the first KB in this model.
     *
     * For example, if this Model has the KB names `['/snap',
     * '/snap/albums']` and this method is called as
     * `model.createModel(['history', '/jibo.loop'])`, then the new
     * model returned by this method will have the KB names
     * `['/snap/history', '/jibo.loop']`.
     *
     * @method jibo.kb.Model#createModel
     * @param {string|string[]} kbNames KB slice names to use in new
     * model.
     * @param {string} [httpUrl] Base URL of KB service to use
     * (defaults to same URL as `this`).
     * @returns {jibo.kb.Model} New Model object
     */
    public createModel(kbNames:string|string[], httpUrl:string=null):Model {
        kbNames = this._toArray(kbNames);
        httpUrl = httpUrl || this.httpUrl;
        let defaultBaseName = this.kbNames[0];
        let newKBNames = [];
        kbNames.forEach( (kbName) => {
            if (!kbName.startsWith('/')) {
                kbName = '/' + defaultBaseName + '/' + kbName;
            }
            newKBNames.push(kbName);
        });
        let ModelClass = Model.findModelClass(newKBNames);
        return new ModelClass(newKBNames, httpUrl);
    }


    /** Create a new empty node on this Model. Will be attached to the
     * first KB in this Model.
     *
     * @method jibo.kb.Model#createNode
     * @param {string} nodeType Node type.
     * @param {Object} [data] Initial data.
     * @returns {jibo.kb.Node} New node object
     */
    public createNode(nodeType:string, data?:any):Node {
        // new nodes come from the first kb in the pool
        let node = this.pool[0].createNode(nodeType, data);
        if (this.cache) {
            this.cache.add(node);
        }
        return node;
    }


    /** Load a node or array of nodes, by their IDs. All KBs in this
     * Model slices are searched in order until found. If node is not
     * found result will be `null`.  If an array is supplied, then
     * multiple IDs are searched for, and an array of results is
     * returned. If callback is omitted, a promise is returned
     * instead.
     *
     * @method jibo.kb.Model#load
     * @param {string|string[]} ids ID or array of IDs to load.
     * @param {Function} [callback] `(err, nodes) => {}`. If callback is
     * omitted, a promise that resolves to `nodes` is returned instead.
     * @returns {Promise} A promise that resolves with the value of
     * `node` if the callback is omitted.
     */
    public load(id:string, callback:NodeCallback);
    public load(ids:string[], callback:NodesCallback);
    public load(id:string):Promise<Node>;
    public load(ids:string[]):Promise<Node[]>;
    @promisify
    public load(ids:string|string[], callback?:NodeCallback|NodesCallback):void|Promise<Node|Node[]> {
        if (!Array.isArray(ids)) {
            this._loadOne(<string>ids, <NodeCallback>callback);
        } else {
            this._loadArray(<string[]>ids, <NodesCallback>callback);
        }
    }


    // these is actaully defined in jibo/src/depreciation.ts, this is just for the typings
    public loadList(ids:string[], callback:NodesCallback);
    public loadList(ids:string[], callback:(err, nodes?:Node[])=>void) {
        // this will only be called if the depreciation method is removed from jibo/src/depreciation.ts
        throw new Error('kb.Model.loadList is an unsupported method, use kb.Model.load');
    }

    // these is actaully defined in jibo/src/depreciation.ts, this is just for the typings
    public fetchList(ids:string[], quietly?: boolean):Node[];
    public fetchList(ids:string[], quietly:boolean=false):Node[] {
        // this will only be called if the depreciation method is removed from jibo/src/depreciation.ts
        throw new Error('kb.Model.fetchList is an unsupported method, use kb.Model.fetch');
    }


    /** Load the root node of the first KB. If a KB slice name is
     * given, then load the root node for that KB instead. If callback
     * is omitted a promise is returned instead.
     *
     * @method jibo.kb.Model#loadRoot
     * @param {string} [kbName] Name of KB slice to load root node
     * from. Default is first slice.
     * @param {Function} [callback] (err, rootNode) => {}. If callback
     * is omitted a promise that resolves to `rootNode` is returned
     * instead.
     * @returns {Promise} A promise that resolves with the value of
     * `rootNode` if the callback is omitted.
     */
    public loadRoot(callback:NodeCallback);
    public loadRoot(kbName:string, callback:NodeCallback);
    public loadRoot():Promise<Node>;
    public loadRoot(kbName:string):Promise<Node>;
    @promisify
    public loadRoot(kbName?:string|NodeCallback, callback?:NodeCallback):void|Promise<Node> {
        // check if just a callback was given and adjust args
        if (typeof kbName === 'function' && !callback) {
            callback = <NodeCallback>kbName;
            kbName = null;
        }

        let knowledgeDatabase:KnowledgeDatabase;
        if (!kbName) {
            knowledgeDatabase = this.pool[0];
        } else {
            knowledgeDatabase = this._getKnowledgeDatabase(<string>kbName);
        }

        if (!knowledgeDatabase) {
            setImmediate( () => {
                let err = new Error('loadRoot kb slice name '+kbName+' not found');
                callback(err);
            });
        } else {
            if (this.cache) {
                let rootNode = this.fetchRoot(<string>kbName, true);
                if (rootNode) {
                    setImmediate( () => {
                        callback(null, rootNode);
                    });
                } else {
                    knowledgeDatabase.loadRoot( (err, loadedRootNode) => {
                        if (!err && loadedRootNode) {
                            this.roots[<string>kbName] = loadedRootNode;
                        }
                        callback(err, loadedRootNode);
                    });
                }
            } else {
                knowledgeDatabase.loadRoot(callback);
            }
        }
    }


    /** Preload all nodes connected by the layer names into the
     * cache. Does not return the nodes. If callback is omitted a
     * promise is returned instead.
     *
     * @method jibo.kb.Model#loadLayers
     * @param {jibo.kb.Node} node Initial node to start from.
     * @param {string|string[]} layers Edge names to follow.
     * @param {Function} [callback] Callback for the method. If callback
     * is omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     */
    public loadLayers(node:Node, layers:string|string[], callback:Function);
    public loadLayers(node:Node, layers:string|string[]):Promise<any>;
    @promisify
    public loadLayers(node:Node, layers:string|string[], callback?:Function):void|Promise<any> {
        let action = (eachNode, callback) => callback();
        this.visitLayers(node, layers, action, callback);
    }


    /** Save all nodes connected by the layer names. Only used after
     * activating the cache and preloading the given layers with
     * loadLayers(). If callback is omitted a promise is returned
     * instead.
     *
     * @method jibo.kb.Model#saveLayers
     * @param {jibo.kb.Node} node Initial node to start from.
     * @param {string|string[]} layers Edge names to follow.
     * @param {Function} [callback] Callback for the method. If callback
     * is omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     */
    public saveLayers(node:Node, layers:string|string[], callback:Function);
    public saveLayers(node:Node, layers:string|string[]):Promise<any>;
    @promisify
    public saveLayers(node:Node, layers:string|string[], callback?:Function):void|Promise<any> {
        let action = (eachNode, callback) => eachNode.save(callback);
        this.visitLayers(node, layers, action, callback);
    }


    /** Load all nodes connected by the layer names. Execute the given
     * action once on each node. If callback is omitted a promise is
     * returned instead.
     *
     * @method jibo.kb.Model#visitLayers
     * @param {jibo.kb.Node} node Initial node to start from.
     * @param {string|string[]} layers Edge names to follow.
     * @param {Function} action `(eachNode, callback) => {}`
     * @param {Function} [callback] Callback for the method. If callback
     * is omitted a promise is returned instead.
     * @returns {Promise} A promise if the callback is omitted.
     */
    public visitLayers(node:Node, layers:string|string[], action:Function, callback:Function);
    public visitLayers(node:Node, layers:string|string[], action:Function):Promise<any>;
    @promisify_4
    public visitLayers(node:Node, layers:string|string[], action:Function, callback?:Function):void|Promise<any> {
        if (!node) {
            return callback();
        }
        // should we note the layers loaded so we can warn on trying to
        // traverse non loaded layers? otherwise it might be concluded
        // that a node doesn't exists when it might just not have been loaded
        layers = this._toArray(layers);
        let visited = {};
        visited[node._id] = true;

        let visitNodes = (idList:string[], callback) => {
            let tasks:AsyncFunction<void>[] = [];
            let queue:string[] = [];
            idList.forEach( (id) => {
                if (!(id in visited)) {
                    visited[id] = true;
                    tasks.push( (next) => {
                        this.load(id, (err, eachNode) => {
                            if (!err && eachNode) {
                                action(eachNode, (err) => {
                                    eachNode.getEdges(<string[]>layers).forEach( (everyId) => {
                                        if (!(everyId in visited)) {
                                            queue.push(everyId);
                                        }
                                    });
                                    next(err);
                                });
                            } else {
                                next(err);
                            }
                        });
                    });
                }
            });
            async.series(tasks, (err /*,results*/) => {
                if (!err && queue.length) {
                    visitNodes(queue, callback);
                } else {
                    callback(err);
                }
            });
        };

        // start things by executing the action on the initial node
        action(node, (err) => {
            log.iferr(err, 'action on initial node failed');
            if (!err) {
                visitNodes(node.getEdges(<string[]>layers), callback);
            } else {
                callback(err);
            }
        });
    }


    /** Create a clone of this Model object and its slices, but with
     * the cache enabled. Cache based operations are intended to be
     * short term in nature. Release the clone for garbage collection
     * when finished.
     *
     * @method jibo.kb.Model#begin
     * @returns {jibo.kb.Model} A new Model object.
     */
    public begin():Model {
        let ourConstructor = <ModelConstructor>this.constructor;  // stops a typescript complaint
        let model = new ourConstructor(this.kbNames, this.httpUrl);  // clone ourself
        model.enableCache();
        return model;  // return our clone with caching enabled
    }


    /** Synchronously fetch a node, or array of nodes, from the
     * cache. Use on models created with `begin()` and preloaded with
     * nodes. Nodes searched for but not found during preloading will
     * be null. Nodes not preloaded will be undefined.
     *
     * @method jibo.kb.Model#fetch
     * @param {string|string[]} ids ID or array of IDs node to fetch.
     * @param {boolean} [quietly] Suppress warning if node not found
     * in cache.
     * @throws Exception if cache is not enabled.
     * @returns {jibo.kb.Node} Node or `null` if not found. If
     * an array of IDs is supplied, then an array of nodes is
     * returned.
     */
    public fetch(id:string, quietly?:boolean):Node;
    public fetch(ids:string[], quietly?:boolean):Node[];
    public fetch(ids:string|string[], quietly:boolean=false):Node|Node[] {
        this._assertCache();
        if (!Array.isArray(ids)) {
            return this.cache.fetch(ids, quietly);
        } else {
            const list:Node[] = [];
            const notFoundIds:string[] = [];
            ids.forEach( (id) => {
                const node = this.cache.fetch(id, true);
                if (node || node === null) {
                    list.push(node);
                } else {
                    list.push(undefined);
                    notFoundIds.push(id);
                }
            });

            if (notFoundIds.length && !quietly) {
                log.warn('fetchList ids were not in cache, skipped', notFoundIds.join(', '));
            }
            return list;
        }
    }


    /** Synchronously fetch the root node of the first KB from cache.
     * If a KB slice name is given, then load the root node for that
     * KB instead.
     *
     * @method jibo.kb.Model#fetchRoot
     * @param {string} [kbName] Name of KB slice to load root node
     * from. Default is first slice.
     * @param {boolean} [quietly] Suppress warning if root node not
     * found in cache.
     * @throws Exception if cache is not enabled.
     * @returns {jibo.kb.Node} Root node or `null` if not in cache.
     */
    public fetchRoot(kbName?:string, quietly:boolean=false):Node {
        this._assertCache();
        if (!kbName) {
            kbName = this.pool[0].kbName;
        }
        let root:Node = null;
        if (this.roots[kbName]) {
            root = this.roots[kbName];
        } else {
            if (!quietly) {
                log.warn('fetchRoot for name', kbName, 'root not in cache');
            }
        }
        return root;
    }


    /** Turn on the cache. Don't call this directly, use begin() instead.
     * @method jibo.kb.Model#enableCache
     * @private
     */
    protected enableCache() {
        this.cache = new Cache();
        this.roots = {};
    }


    /** Actual load command. Wrapped by interceptLoad when cache is
     * enabled.
     *
     * @method jibo.kb.Model#_load
     * @param {string} id Id of node to load
     * @param {Function} callback (err, node) => {}
     * @private
     */
    private _load(id:string, callback:NodeCallback) {
        const tasks:Function[] = [];
        this.pool.forEach( (knowledgeDatabase) => {
            tasks.push( (node, next) => {

                // a quirk of the first call via async.waterfall (no inital args)
                if (!next) { next = node; node = null; }

                if (!node) {  // if not found by a previous task
                    knowledgeDatabase.load(id, (err, node) => {
                        //log.iferr(err, 'load (not in cache)');
                        next(err, node);
                    });
                } else {  // it was found, just pass it along
                    next(null, node);
                }
            });
        });
        async.waterfall(tasks, callback);
    }


    /** Load a single node by its id. All KBs in this
     * Model will be searched in order until found. Null returned (via
     * callback) if not found.
     *
     * @method jibo.kb.Model#_loadOne
     * @param {string} id ID to load.
     * @param {Function} [callback] (err, node) => {}.
     * @private
     */
    private _loadOne(id:string, callback:NodeCallback) {
        if (this.cache) {
            this.cache.interceptLoad(id, callback, (missingId, cacheCallback) => {
                this._load(missingId, cacheCallback);
            });
        } else {
            this._load(id, callback);
        }
    }


    /** Load an array of nodes by id. All KBs in this Model will be
     * searched, in order, for each id in the array. An array is always
     * returned, with the same length as the ids parameter. Nodes are
     * returned in the array in the same order requested. Any not-found
     * IDs will return a null in place of its node at the proper array
     * position.
     *
     * @method jibo.kb.Model#_loadArray
     * @param {string[]} ids Array of IDs of nodes to load.
     * @param {Function} [callback] (err, nodes) => {}.
     * @private
     */
    private _loadArray(ids:string[], callback:NodesCallback) {
        // Create a map of nodes by their ID, for storing results of
        // cache fetching or KB loading
        const nodes:Map<string, Node> = new Map<string, Node>();
        // Clone the ids array to keep track of which we don't find in the cache
        const remainingIDs:string[] = ids.slice(0);
        // If we have have a cache, try to fetch each node from the cache first
        if(this.cache) {
            // This is passed as the `load` arg to Cache#interceptLoad, and
            // just always and immediately returns a null result
            const fakeLoad = (id:string, callback:NodeCallback) =>
                setImmediate(() => callback(null, null));
            // Iterate over the IDs to check if it's in the cache
            ids.forEach(id => {
                // This is called and either passed a found node from the
                // cache, or the `null` that came from our `fakeLoad`
                const addNode = (err, node) => {
                    if(node) {
                        // Add the cached node to the results map by its ID
                        nodes[id] = node;
                        // Remove the ID from the clone of the ids param
                        // so that we don't load anything from disk that
                        // we already have from cache
                        remainingIDs.splice(remainingIDs.indexOf(id), 1);
                    }
                };
                // We call Cache#interceptLoad because it uses a private
                // method to explicitly place a null in the cache; if the cache
                // is prefetched, we need to ensure a null is placed for that
                // ID in the cache; we may overwrite the null when we call
                // loadList below.
                this.cache.interceptLoad(id, addNode, fakeLoad);
            });
        }
        // This function is passed to async.map; it retrieves a list of nodes
        // from a given KB slice; any not found will be null
        function getNodes(
            slice:KnowledgeDatabase,
            callback:NodesCallback
        ):void {
            slice.loadList(remainingIDs, callback);
        }
        // For each KB slice (this.pool is a slice[]), call getNodes in
        // parallel; allSlicesResults here is an array of node arrays,
        // each containing the result (a node[]) of calling getNode for
        // that slice
        async.map(this.pool, getNodes, (err, allSlicesResults) => {
            // Per `async` documentation, `results` array passed to
            // the callback in `map` is guaranteed to be in the
            // same order as the original collection mapped over
            // https://caolan.github.io/async/docs.html#map
            // For each KB slice result (each of which is a node[])
            allSlicesResults.forEach(nodesForSlice => {
                // For each node in that slice's result
                nodesForSlice.forEach(node => {
                    // Ignore any result that isn't truthy
                    // (it may exist in another slice)
                    // If we've already found a node for this ID in a
                    // previous slice, don't overwrite it, so we have
                    // predictable behavior (first slice added to the pool
                    // wins)
                    if(node && !nodes[node._id]) {
                        // Add it to the nodes result map by its ID
                        nodes[node._id] = node;
                        // Also add it to the node cache
                        if(this.cache) {
                            this.cache.add(node);
                        }
                    }
                });
            });
            // Now we map over the ids passed into this method, so that we
            // return an array of the same length, with its node (or null)
            // results in the proper order
            callback(null, ids.map(id => nodes[id] || null));
        });
    }


    /** Look through the pool and return the kb slice
     * that has the given name
     *
     * @method jibo.kb.Model#_getKnowledgeDatabase
     * @param {string} kbName Name of kb slice to find in pool
     * @returns {jibo.kb.KnowledgeDatabase} Matching kb slice object, or
     * undefined if not found
     * @private
     */
    private _getKnowledgeDatabase(kbName:string):KnowledgeDatabase {
        let knowledgeDatabase;
        for (let n=0; n<this.pool.length; n++) {
            if (kbName === this.pool[n].kbName) {
                knowledgeDatabase = this.pool[n];
                break;
            }
        }
        return knowledgeDatabase;
    }



    /** check if cache is enabled and throw exception if not
     *
     * @method jibo.kb.Model#_assertCache
     * @private
     */
    private _assertCache() {
        if (!this.cache) {
            throw new Error('fetch method called on a Model without a cache');
        }
    }


    /** Convert a single item to an array for arguments that may be a
     * single thing or an array of things
     *
     * @method jibo.kb.Model#<_toArray
     * @private
     */
    private _toArray<T>(items:T|T[]):T[] {
        if (!Array.isArray(items)) {
            return [items];  // separate returns makes typescript happy
        } else {
            return items;
        }
    }
}
