import Node from './Node';

export type LocationOverride = {
    city: string,
    state: string,
    stateAbbr: string,
    country: string,
    lat: number,
    lng: number,
};


/**
 * @class RobotRootNode
 * @extends jibo.kb.Node
 * @memberof jibo.kb.robot
 */
export default class RobotRootNode extends Node {
    public data: {
        // from base record
        id: string,
        updated: number,
        created: number,
        // from .payload
        avatar?: number,
        serialNumber?: string,
        platform?: string,
        connectedAt?: number,
        SSID?: string,
        locationOverride?: LocationOverride,
    };

    /**
     * Get location override info if it has been set by the app.
     * @name jibo.kb.robot.RobotRootNode#locationOverride
     * @type {String}
     */
    public get locationOverride():LocationOverride {
        return this.data.locationOverride;
    }
}
