import Model from './Model';
import RobotModelEvents from './RobotModelEvents';
import {WSClient} from 'jibo-client-framework';


export type ErrCallback = (err)=>void;

/**
 * Jibo KB Robot Properties API
 * @namespace jibo.kb.robot
 */

/** RobotModel Class. The Robot Model subclass
 *
 * @class RobotModel
 * @extends jibo.kb.Model
 * @memberof jibo.kb.robot
 * @example
 * let model = jibo.kb.robot.createModel('/jibo/robot');
 */
export default class RobotModel extends Model {
    /**
     * Strongly-typed events emitted by this model
     * @intdocs
     * @name jibo.kb.robot.events
     * @type {jibo.kb.robot.RobotModelEvents}
     */
    public events = new RobotModelEvents();

    // WebSocket client for listening for events from KBService
    private _wsClient: WSClient;


    constructor(kbNames:string|string[], httpUrl:string=null) {
        super(kbNames, httpUrl);
        this._listenForWSMessages();
    }


    // Listen for WebSocket messages from the KBService
    private _listenForWSMessages(): void {
        this._wsClient = new WSClient(this.httpUrl);
        this._wsClient.on('message', this._wsMessageReceived.bind(this));
    }


    // Message receipt handler for WebSocket messages from KBService
    private _wsMessageReceived(message) {
        switch(message) {
            case 'RobotUpdated':
                console.log('RobotModel: received RobotUpdated event; emitting RobotModelEvents.robotUpdate');
                this.events.robotUpdated.emit();
                break;
            default:
                console.warn('RobotModel: received unknown message from KBService', message);
        }
    }
}
